    private func openCamera(callbackId: String?) {
        checkCameraPermission { [weak self] granted in
            guard let self = self else { return }
            
            if granted {
                DispatchQueue.main.async {
                    let picker = UIImagePickerController()
                    picker.sourceType = .camera
                    picker.delegate = self
                    picker.allowsEditing = false
                    self.present(picker, animated: true)
                    self.sendCallback(callbackId: callbackId, success: true, data: nil)
                }
            } else {
                self.sendCallback(callbackId: callbackId, success: false, data: ["error": "Camera permission denied"])
            }
        }
    }
    
    private func requestCameraPermission(callbackId: String?) {
        AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
            self?.sendCallback(callbackId: callbackId, success: granted, data: ["granted": granted])
        }
    }
    
    private func checkCameraPermission(completion: @escaping (Bool) -> Void) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        
        switch status {
        case .authorized:
            completion(true)
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { granted in
                completion(granted)
            }
        default:
            completion(false)
        }
    }
    
    private func registerPushNotifications(callbackId: String?) {
        UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
            if settings.authorizationStatus == .authorized {
                DispatchQueue.main.async {
                    UIApplication.shared.registerForRemoteNotifications()
                    self?.sendCallback(callbackId: callbackId, success: true, data: ["status": "authorized"])
