    }
    
    private func getProductInfo(productIds: [String], callbackId: String?) {
        let request = SKProductsRequest(productIdentifiers: Set(productIds))
        
        productRequestCallback = { [weak self] success, products in
            if success, let products = products {
                let productsData = products.map { product -> [String: Any] in
                    return [
                        "productId": product.productIdentifier,
                        "title": product.localizedTitle,
                        "description": product.localizedDescription,
                        "price": product.price.doubleValue,
                        "priceLocale": product.priceLocale.currencyCode ?? "",
                        "priceString": self?.formatPrice(product) ?? ""
                    ]
                }
                self?.sendCallback(callbackId: callbackId, success: true, data: ["products": productsData])
            } else {
                self?.sendCallback(callbackId: callbackId, success: false, data: ["error": "Failed to fetch products"])
            }
        }
        
        let delegate = ProductRequestDelegate(callback: productRequestCallback!)
        request.delegate = delegate
        request.start()
    }
    
    private func formatPrice(_ product: SKProduct) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.locale = product.priceLocale
        return formatter.string(from: product.price) ?? ""
    }
    
    private func purchaseProduct(productId: String, callbackId: String?) {
        let request = SKProductsRequest(productIdentifiers: [productId])
        
        productRequestCallback = { [weak self] success, products in
            if success, let product = products?.first {
                let payment = SKPayment(product: product)
                SKPaymentQueue.default().add(payment)
                
                self?.purchaseCallback = { success, transactionId in
                    self?.sendCallback(callbackId: callbackId, success: success, data: [
                        "transactionId": transactionId ?? "",
                        "productId": productId
                    ])
                }
            } else {
                self?.sendCallback(callbackId: callbackId, success: false, data: ["error": "Product not found"])
            }
        }
        
        let delegate = ProductRequestDelegate(callback: productRequestCallback!)
        request.delegate = delegate
        request.start()
    }
    
    private func restorePurchases(callbackId: String?) {
        SKPaymentQueue.default().restoreCompletedTransactions()
        sendCallback(callbackId: callbackId, success: true, data: ["message": "Restore initiated"])
