    private func setupStoreKitObserver() {
        SKPaymentQueue.default().add(StoreKitTransactionObserver(delegate: self))
    }
    
    private func sendCallback(callbackId: String?, success: Bool, data: [String: Any]?) {
        guard let callbackId = callbackId else { return }
        
        var response: [String: Any] = [
            "success": success,
            "callbackId": callbackId
        ]
        
        if let data = data {
            response["data"] = data
        }
        
        if let jsonData = try? JSONSerialization.data(withJSONObject: response, options: []),
           let jsonString = String(data: jsonData, encoding: .utf8) {
            let script = "window.nativeCallback(\(jsonString));"
            DispatchQueue.main.async { [weak self] in
                self?.webView.evaluateJavaScript(script, completionHandler: nil)
            }
        }
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        injectBridgeScript()
    }
    
    private func injectBridgeScript() {
        let script = """
        window.nativeApp = {
            call: function(action, params, callback) {
                var callbackId = 'cb_' + Date.now() + '_' + Math.random();
                if (callback) {
                    window.nativeCallbacks = window.nativeCallbacks || {};
                    window.nativeCallbacks[callbackId] = callback;
                }
                window.webkit.messageHandlers.nativeApp.postMessage({
                    action: action,
                    params: params,
                    callbackId: callbackId
                });
            }
        };
        
        window.nativeCallback = function(response) {
            if (window.nativeCallbacks && window.nativeCallbacks[response.callbackId]) {
                window.nativeCallbacks[response.callbackId](response);
                delete window.nativeCallbacks[response.callbackId];
            }
        };
        """
        
        webView.evaluateJavaScript(script, completionHandler: nil)
    }
    
