class ProductRequestDelegate: NSObject, SKProductsRequestDelegate {
    private let callback: (Bool, [SKProduct]?) -> Void
    
    init(callback: @escaping (Bool, [SKProduct]?) -> Void) {
        self.callback = callback
    }
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        callback(true, response.products)
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        callback(false, nil)
    }
}

protocol StoreKitTransactionDelegate: AnyObject {
    func transactionCompleted(transaction: SKPaymentTransaction)
    func transactionFailed(transaction: SKPaymentTransaction)
}

class StoreKitTransactionObserver: NSObject, SKPaymentTransactionObserver {
    weak var delegate: StoreKitTransactionDelegate?
    
    init(delegate: StoreKitTransactionDelegate) {
        self.delegate = delegate
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                SKPaymentQueue.default().finishTransaction(transaction)
                delegate?.transactionCompleted(transaction: transaction)
            case .failed:
                SKPaymentQueue.default().finishTransaction(transaction)
                delegate?.transactionFailed(transaction: transaction)
            case .restored:
                SKPaymentQueue.default().finishTransaction(transaction)
                delegate?.transactionCompleted(transaction: transaction)
            case .deferred, .purchasing:
                break
            @unknown default:
                break
            }
        }
    }
}

extension AppDelegate {
